define('block_blumod/assign_resources',[],function(){const MIN_FILTER_CHARS=3;function init(){const e=document.getElementById('bluselector'),t=document.getElementById('resources');if(!e||!t)return;e.value&&(asignarBlu(e.value),llamarresources(e.value)),e.addEventListener('change',function(e){asignarBlu(e.target.value),llamarresources(e.target.value)}),document.querySelectorAll('.validate-selected').forEach(function(t){t.addEventListener('click',function(t){if(!e.value){t.preventDefault()}})}),t.addEventListener('click',function(t){const n=t.target.closest('button[data-action][data-from]');n&&executeAction(n.dataset.action,n.dataset.from,e)})}function executeAction(e,t,n){if(!e||!t||!n.value)return;const o=document.getElementById(t);if(!o||!o.value)return;const r=n.value;asignarBlu(r),llamarresources(r,e,o.value)}function asignarBlu(e){document.querySelectorAll('[name=id]').forEach(function(t){t.value=e})}function llamarresources(e,t,n){const o=(new URLSearchParams(window.location.search)).get('courseid');if(!o)return;const r=new URLSearchParams({courseid:o,id:e});t&&n&&(r.set('action',t),r.set('modid',n));const a=M.cfg.wwwroot+'/blocks/blumod/resources.php?'+r.toString();fetch(a).then(function(e){return e.text()}).then(function(e){const t=document.getElementById('resources');t&&(t.innerHTML=e,bindSearchFilter())}).catch(function(){console.log('Error fetching resources')})}function bindSearchFilter(){const e=document.getElementById('resourceselector_search'),t=document.getElementById('resourceselector_available');if(!e||!t)return;applySearchFilter(e,t),e.addEventListener('input',function(){applySearchFilter(e,t)})}function applySearchFilter(e,t){const n=e.value.trim().toLowerCase(),o=n.length>=MIN_FILTER_CHARS;Array.prototype.forEach.call(t.options,function(e){o?e.hidden=e.text.toLowerCase().indexOf(n)===-1:e.hidden=false})}return{init:init}});